#include<bits/stdc++.h>
using namespace std;
long long p[100010],root[100010],fa[100010][21];
long long d[100010],lg[100010],u[100010],v[100010];
vector<long long> mp[100010];
vector<long long> vec[100010];
map<long long,long long> mp1;
long long n,m,q;
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long sums,sumg;
    }a[6000010];
    void pushup(long long x)
    {
        a[x].sums=a[a[x].lson].sums+a[a[x].rson].sums;
        a[x].sumg=a[a[x].lson].sumg+a[a[x].rson].sumg;
    }
    long long cnt;
    segment_tree():cnt(0){}
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sums=0;
            a[x].sumg=0;
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    long long add(long long x,long long p,long long val)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return x;
        }
        long long now=++cnt;
        a[now]=a[x];
        if(a[x].l==a[x].r)
        {
            a[now].sums+=val;
            a[now].sumg++;
            return now;
        }
        a[now].lson=add(a[x].lson,p,val);
        a[now].rson=add(a[x].rson,p,val);
        pushup(now);
        return now;
    }
    long long query(long long x,long long y,long long lca,long long lcaf,long long val)
    {
        if(a[x].l==a[x].r)
        {
            long long t=p[a[x].l];
            long long sum=a[x].sumg+a[y].sumg-a[lca].sumg-a[lcaf].sumg;
            if(val/t>sum)
            {
                return 0;
            }
            return sum-val/t;
        }
        long long sum=a[a[x].lson].sums+a[a[y].lson].sums-a[a[lca].lson].sums-a[a[lcaf].lson].sums;
        if(sum<=val)
        {
            return query(a[x].rson,a[y].rson,a[lca].rson,a[lcaf].rson,val-sum);
        }
        else
        {
            return a[a[x].rson].sumg+a[a[y].rson].sumg-a[a[lca].rson].sumg-a[a[lcaf].rson].sumg+query(a[x].lson,a[y].lson,a[lca].lson,a[lcaf].lson,val);
        }
    }
}t;
void dfs(long long x,long long f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(long long i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
}
void dfs2(long long x,long long fa=0)
{
    root[x]=root[fa];
    for(long long i:vec[x])
    {
        root[x]=t.add(root[x],mp1[i],i);
    }
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            dfs2(i,x);
        }
    }
}
long long lca(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(long long i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
int main()
{
    scanf("%lld%lld%lld",&n,&m,&q);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=__lg(i);
        scanf("%lld%lld",&u[i],&v[i]);
        mp[u[i]].push_back(v[i]);
        mp[v[i]].push_back(u[i]);
    }
    dfs(1);
    long long k=0;
    for(long long i=1;i<=m;i++)
    {
        long long p,c;
        scanf("%lld%lld",&p,&c);
        p++;
        long long a=u[p],b=v[p];
        if(d[a]<d[b])
        {
            swap(a,b);
        }
        vec[a].push_back(c);
        ::p[++k]=c;
    }
    sort(p+1,p+1+k);
    k=unique(p+1,p+1+k)-p-1;
    for(long long i=1;i<=k;i++)
    {
        mp1[p[i]]=i;
    }
    root[0]=t.init(1,k);
    dfs2(1);
    while(q--)
    {
        long long u,v,x,y;
        scanf("%lld%lld%lld%lld",&u,&v,&x,&y);
        long long l=lca(u,v);
        long long p=t.query(root[u],root[v],root[l],root[l],y);
        if(p>x)
        {
            printf("-1\n");
        }
        else
        {
            printf("%lld\n",x-p);
        }
    }
    return 0;
}
